mapper.select:
select h.id as id, h.title as title, h.content as content, h.course_id as courseId, c.course_name as courseName, h.teacher_id as teacherId, u.real_name as teacherName, h.publish_time as publishTime, h.deadline as deadline from homework h left join course c on h.course_id = c.id left join user u on h.teacher_id = u.id where h.course_id in
#{id}
order by h.id desc

mapper.update:
update homework



    title = #{title},

    content = #{content},

    deadline = #{deadline},

    status = #{status}



where id = #{id}

mapper.select:
select count(*)
from homework h
         left join user_course uc on h.course_id = uc.course_id
         left join homework_submit hs on h.id = hs.homework_id and hs.student_id = #{studentId}
where uc.user_id = #{studentId}
  and h.deadline > #{now}
  and hs.id is null
